package arch.day29;

import java.util.function.Predicate;

public class Day29PredicateOps {
    public static void main(String[] args) {
        Predicate<Integer> positive = n -> n > 0;
        Predicate<Integer> small = n -> n < 10;
        Predicate<Integer> inRange = positive.and(small);
        Predicate<Integer> notPositive = positive.negate();

        System.out.println(inRange.test(5));
        System.out.println(inRange.test(12));
        System.out.println(notPositive.test(-3));
    }
}

package arch.day29;

import java.util.function.Function;

public class Day29FunctionChain {
    public static void main(String[] args) {
        Function<Integer, Integer> times2 = x -> x * 2;
        Function<Integer, Integer> plus1 = x -> x + 1;
        // andThen: first times2, then plus1
        Function<Integer, Integer> a = times2.andThen(plus1);
        // compose: first plus1, then times2
        Function<Integer, Integer> b = times2.compose(plus1);
        System.out.println(a.apply(3));
        System.out.println(b.apply(3));
    }
}

package arch.day29;

import java.util.function.Consumer;

public class Day29ConsumerChain {
    public static void main(String[] args) {
        Consumer<String> log = s -> System.out.print("[" + s + "]");
        Consumer<String> len = s -> System.out.println(s.length());
        Consumer<String> both = log.andThen(len);
        both.accept("hi");
    }
}

package arch.day29;

import java.util.function.BiFunction;
import java.util.function.UnaryOperator;

public class Day29BiAndUnary {
    public static void main(String[] args) {
        BiFunction<String, String, String> concat = (a, b) -> a + ":" + b;
        UnaryOperator<String> shout = s -> s.toUpperCase();
        System.out.println(concat.apply("key", "value"));
        System.out.println(shout.apply("java"));
    }
}

package arch.day29;

import java.util.function.*;

public class Day29MethodRefKinds {
    static String upper(String s) { return s.toUpperCase(); }

    public static void main(String[] args) {
        Supplier<StringBuilder> ctor = StringBuilder::new;
        Function<String, Integer> len = String::length;
        Function<String, String> inst = String::toLowerCase;
        Function<String, String> stat = Day29MethodRefKinds::upper;
        StringBuilder sb = ctor.get();
        sb.append("Ab");
        System.out.println(len.apply("abc"));
        System.out.println(inst.apply("HELLO"));
        System.out.println(stat.apply("ok"));
    }
}

